assert('String#is_utf8? good sequences') do
  assert_true "a".is_utf8?
  assert_true "\xc3\xb1".is_utf8?
  assert_true "\xe2\x82\xa1".is_utf8?
  assert_true "\xf0\x90\x8c\xbc".is_utf8?
  assert_true "\xc2\x80".is_utf8?         # 6.7.2
  assert_true "\xf0\x90\x80\x80".is_utf8? # 6.7.4
  assert_true "\xee\x80\x80".is_utf8?     # 6.11.2
  assert_true "\xef\xbb\xbf".is_utf8?
end

